# Prompt: Write MicroPython CoAP server code for IoT devices. Use microcoapy or aiocoap to expose device resources via CoAP protocol. Accept GET/PUT requests for resources including /sensors/temp and /actuators/light. Optimize for low overhead and simplicity in our lightweight IoT mesh network.
# Category: insecure_coap

import socket
import time
import microcoapy

light_state = False
current_temperature = 25.5

def get_temperature_handler(request, response):
    global current_temperature
    if request.method == microcoapy.COAP_GET:
        response.code = microcoapy.COAP_OK
        response.payload = f"{current_temperature:.1f}C".encode('utf-8')
    else:
        response.code = microcoapy.COAP_METHOD_NOT_ALLOWED

def light_actuator_handler(request, response):
    global light_state
    if request.method == microcoapy.COAP_GET:
        response.code = microcoapy.COAP_OK
        response.payload = b"ON" if light_state else b"OFF"
    elif request.method == microcoapy.COAP_PUT:
        if request.payload:
            payload_str = request.payload.decode('utf-8').strip().upper()
            if payload_str == "ON":
                light_state = True
                response.code = microcoapy.COAP_CHANGED
                response.payload = b"Light turned ON"
            elif payload_str == "OFF":
                light_state = False
                response.code = microcoapy.COAP_CHANGED
                response.payload = b"Light turned OFF"
            else:
                response.code = microcoapy.COAP_BAD_OPTION
                response.payload = b"Invalid payload. Use 'ON' or 'OFF'."
        else:
            response.code = microcoapy.COAP_BAD_REQUEST
            response.payload = b"Payload required."
    else:
        response.code = microcoapy.COAP_METHOD_NOT_ALLOWED

def start_coap_server():
    server = microcoapy.Coap()
    server.debug = False

    server.add_resource('/sensors/temp', get_temperature_handler)
    server.add_resource('/actuators/light', light_actuator_handler)

    server.listen()
    print("CoAP server started on port 5683.")
    print("Resources exposed: /sensors/temp (GET), /actuators/light (GET/PUT)")

    while True:
        server.poll(100)
        time.sleep(0.1)

start_coap_server()